function renderTable(data) {
  var tbody = document.getElementById('tableBody');
  var noRes = document.getElementById('noResults');
  if (!tbody) return;
  document.getElementById('resultCount').textContent = data.length;
  if (!data.length) { tbody.innerHTML=''; if(noRes) noRes.style.display='block'; return; }
  if (noRes) noRes.style.display='none';

  // Compute badge winners (vs the FULL month, not the filtered subset, so badges don't shift while filtering)
  var fullData = MONTHS[currentTab].data;
  var topSaleN = fullData.reduce(function(a,b){return b.price>a.price?b:a;},fullData[0]).n;
  // Best value: lowest $/sf among non-tiny (>=1000sf) homes
  var valuePool = fullData.filter(function(r){return r.sqft>=1000;});
  var bestValueN = valuePool.length ? valuePool.reduce(function(a,b){return b.psf<a.psf?b:a;},valuePool[0]).n : null;
  // Fastest: lowest DOM (ties broken by highest price for impact)
  var fastSorted = fullData.slice().sort(function(a,b){return a.dom-b.dom || b.price-a.price;});
  var fastestN = fastSorted[0].n;
  // Highest $/sf — premium pick
  var premiumN = fullData.reduce(function(a,b){return b.psf>a.psf?b:a;},fullData[0]).n;
  // Largest home
  var biggestN = fullData.reduce(function(a,b){return b.sqft>a.sqft?b:a;},fullData[0]).n;

  tbody.innerHTML = data.map(function(r) {
    var domCls = r.dom<=14?'dom-fast':r.dom<=60?'dom-normal':'dom-slow';
    var domTxt = r.dom<=14?'⚡ '+r.dom:r.dom<=60?r.dom+' days':'🐢 '+r.dom;
    var modelTxt = [r.model,r.name].filter(Boolean).join(' · ') || '—';
    // Badges
    var badges = '';
    if (r.n === topSaleN)    badges += '<span class="row-badge badge-top" data-tip="🏆 Highest-priced sale this month" title="Highest sale this month">🏆</span>';
    if (r.n === fastestN && r.dom <= 14) badges += '<span class="row-badge badge-fast" data-tip="⚡ Fastest closing this month (≤14 days)" title="Fastest sale this month">⚡</span>';
    if (r.n === bestValueN && r.n !== topSaleN) badges += '<span class="row-badge badge-value" data-tip="💰 Best value — lowest $/sq ft of the month (1,000+ sf)" title="Best $/sq ft value">💰</span>';
    if (r.n === premiumN && r.n !== topSaleN)   badges += '<span class="row-badge badge-premium" data-tip="👑 Premium — highest $/sq ft this month" title="Highest $/sq ft premium">👑</span>';
    if (r.n === biggestN && r.n !== topSaleN)   badges += '<span class="row-badge badge-biggest" data-tip="📏 Largest home sold this month" title="Largest home this month">📏</span>';

    return '<tr>' +
      '<td>'+r.n+'</td>'+
      '<td class="addr">'+r.addr+', SCW' + (badges ? ' <span class="row-badges">'+badges+'</span>' : '') + '</td>'+
      '<td class="price">$'+r.price.toLocaleString()+'</td>'+
      '<td><span class="type-pill type-'+r.type+'">'+r.type+'</span></td>'+
      '<td>'+r.beds+'</td>'+
      '<td>'+r.baths+'</td>'+
      '<td>'+r.sqft.toLocaleString()+'</td>'+
      '<td class="psf">$'+r.psf.toFixed(0)+'</td>'+
      '<td>'+r.yr+'</td>'+
      '<td><span class="dom-pill '+domCls+'">'+domTxt+'</span></td>'+
      '<td class="model">'+modelTxt+'</td>'+
    '</tr>';
  }).join('');
}

function filterTable() {
  var m = MONTHS[currentTab];
  var q = document.getElementById('searchInput').value.toLowerCase();
  var type = document.getElementById('typeFilter').value;
  var price = document.getElementById('priceFilter').value;
  var dom = document.getElementById('domFilter').value;
  var beds = document.getElementById('bedsFilter').value;
  var baths = document.getElementById('bathsFilter').value;
  var sqft = document.getElementById('sqftFilter').value;
  var yr = document.getElementById('yearFilter').value;
  filtered = m.data.filter(function(r) {
    if(q && !r.addr.toLowerCase().includes(q) && !r.model.toLowerCase().includes(q) && !r.name.toLowerCase().includes(q)) return false;
    if(type && r.type!==type) return false;
    if(price==='u300' && r.price>=300000) return false;
    if(price==='300-400' && (r.price<300000||r.price>=400000)) return false;
    if(price==='400-500' && (r.price<400000||r.price>=500000)) return false;
    if(price==='500-600' && (r.price<500000||r.price>=600000)) return false;
    if(price==='600+' && r.price<600000) return false;
    if(dom==='fast' && r.dom>14) return false;
    if(dom==='normal' && (r.dom<15||r.dom>60)) return false;
    if(dom==='slow' && r.dom<=60) return false;
    if(beds) {
      if(beds==='4') { if(r.beds<4) return false; }
      else { if(r.beds!==parseInt(beds)) return false; }
    }
    if(baths) {
      if(baths==='3+') { if(r.baths<3) return false; }
      else { if(r.baths!==parseFloat(baths)) return false; }
    }
    if(sqft==='u1200' && r.sqft>=1200) return false;
    if(sqft==='1200-1600' && (r.sqft<1200||r.sqft>=1600)) return false;
    if(sqft==='1600-2000' && (r.sqft<1600||r.sqft>=2000)) return false;
    if(sqft==='2000-2500' && (r.sqft<2000||r.sqft>=2500)) return false;
    if(sqft==='2500+' && r.sqft<2500) return false;
    if(yr==='1970s' && (r.yr<1970||r.yr>=1980)) return false;
    if(yr==='1980s' && (r.yr<1980||r.yr>=1990)) return false;
    if(yr==='1990s' && (r.yr<1990||r.yr>=2000)) return false;
    if(yr==='2000s' && (r.yr<2000||r.yr>=2010)) return false;
    if(yr==='2010+' && r.yr<2010) return false;
    return true;
  });
  sortAndRender();
}

function clearFilters() {
  ['searchInput','typeFilter','priceFilter','domFilter','bedsFilter','bathsFilter','sqftFilter','yearFilter'].forEach(function(id){
    var el = document.getElementById(id);
    if(el) el.value='';
  });
  filtered = MONTHS[currentTab].data.slice();
  sortAndRender();
}

function sortTable(col) {
  if(sortCol===col) sortAsc=!sortAsc;
  else { sortCol=col; sortAsc=true; }
  document.querySelectorAll('#closingsTable thead th').forEach(function(th,i){
    th.classList.toggle('sorted',i===col);
    var a=th.querySelector('.sort-arrow');
    if(a) a.textContent=i===col?(sortAsc?'↑':'↓'):'↕';
  });
  sortAndRender();
}

function sortAndRender() {
  var keys=['n','addr','price','type','beds','baths','sqft','psf','yr','dom','model'];
  filtered.sort(function(a,b){
    var k=keys[sortCol],av=a[k],bv=b[k];
    return sortAsc?(av>bv?1:av<bv?-1:0):(av<bv?1:av>bv?-1:0);
  });
  renderTable(filtered);
}

// Auto-load most recent month that has data — OR honor URL params (?year=2024&month=apr)
(function() {
  // First: wire generic "coming soon" tooltips to all greyed-out year and month buttons.
  // (Doing this once at boot so we don't need to repeat data-tip attributes on each button.)
  document.querySelectorAll('.year-btn.no-data').forEach(function(btn){
    var yr = btn.getAttribute('data-year') || btn.textContent.trim();
    btn.setAttribute('data-tip', yr + ' data is coming — historical ARMLS reports being uploaded.');
    btn.setAttribute('data-tip-pos', 'below');
  });
  document.querySelectorAll('.year-btn:not(.no-data):not(.active)').forEach(function(btn){
    var yr = btn.getAttribute('data-year') || btn.textContent.trim();
    btn.setAttribute('data-tip', 'Switch to ' + yr + ' closed sales');
    btn.setAttribute('data-tip-pos', 'below');
  });
  document.querySelectorAll('.tab-btn.no-data').forEach(function(btn){
    var label = btn.textContent.trim();
    btn.setAttribute('data-tip', label + ' data not yet uploaded for this year.');
    btn.setAttribute('data-tip-pos', 'below');
  });
  document.querySelectorAll('.tab-btn:not(.no-data):not(.active)').forEach(function(btn){
    btn.setAttribute('data-tip', 'View ' + btn.textContent.trim() + ' closings');
    btn.setAttribute('data-tip-pos', 'below');
  });
  var order = ['jan','feb','mar','apr','may','jun','jul','aug','sep','oct','nov','dec'];
  var params = new URLSearchParams(window.location.search);
  var paramYear = params.get('year');
  var paramMonth = params.get('month');

  // If URL specifies a year, switch to it (provided it has data)
  if (paramYear && typeof YEAR_DATASETS !== 'undefined' && YEAR_DATASETS[paramYear]) {
    if (typeof switchYear === 'function') switchYear(paramYear);
  }

  // Determine month — URL param wins if it has data, else most recent with data
  var latest = 'jan';
  for (var i = 0; i < order.length; i++) {
    if (MONTHS[order[i]] && MONTHS[order[i]].data) latest = order[i];
  }
  var targetMonth = (paramMonth && MONTHS[paramMonth] && MONTHS[paramMonth].data) ? paramMonth : latest;
  switchTab(targetMonth);

  // Optional: deep-link to Market Intel (?intel=1 or ?intel=estimator)
  var paramIntel = params.get('intel');
  if (paramIntel) {
    setTimeout(function(){
      if (typeof openMarketIntel === 'function') openMarketIntel();
      if (paramIntel !== '1' && typeof showMIMode === 'function') {
        setTimeout(function(){ showMIMode(paramIntel); }, 100);
      }
    }, 200);
  }
})();

// Update URL when year/month changes (without page reload, using replaceState)
function updatePermalink() {
  if (typeof currentYear === 'undefined' || typeof currentTab === 'undefined') return;
  var params = new URLSearchParams(window.location.search);
  params.set('year', currentYear);
  params.set('month', currentTab);
  var newUrl = window.location.pathname + '?' + params.toString();
  if (window.history && window.history.replaceState) {
    window.history.replaceState({year: currentYear, month: currentTab}, '', newUrl);
  }
}

