      '<div class="active-stat"><div class="active-stat-num">' + pendings.length + '</div><div class="active-stat-lbl">Pending</div></div>' +
      (medianPrice ? '<div class="active-stat"><div class="active-stat-num">' + fmtListPrice(medianPrice) + '</div><div class="active-stat-lbl">Median Ask</div></div>' : '') +
      (avgDom ? '<div class="active-stat"><div class="active-stat-num">' + avgDom + 'd</div><div class="active-stat-lbl">Avg DOM</div></div>' : '');
